    async validateErrorRate() {
        const totalErrors = this.errorLog.length;
        const correctedErrors = this.corrections.filter(c => c.success).length;
        const errorRate = totalErrors > 0 ? (correctedErrors / totalErrors) : 1;
        
        return {
            healthy: errorRate >= 0.8, // 80% correction rate
            totalErrors,
            correctedErrors,
            errorRate: Math.round(errorRate * 100)
        };
    }

    async validatePerformance() {
        const currentMemory = await this.getMemoryUsage();
        const baselineMemory = this.performanceBaseline.get('Memory Usage');
        
        if (baselineMemory) {
            const improvement = baselineMemory.initial - currentMemory;
            const improvementRate = improvement / baselineMemory.initial;
            
            return {
                healthy: improvementRate >= 0.1, // 10% improvement
                currentMemory,
                baselineMemory: baselineMemory.initial,
                improvement: Math.round(improvement),
                improvementRate: Math.round(improvementRate * 100)
            };
        }
        
        return { healthy: true, currentMemory };
    }

    async validateStability() {
        const recentErrors = this.errorLog.filter(error => 
            Date.now() - error.timestamp < 60000 // Last minute
        );
        
        return {
            healthy: recentErrors.length < 5, // Less than 5 errors per minute
            recentErrors: recentErrors.length,
            stabilityScore: Math.max(0, 100 - (recentErrors.length * 20))
        };
    }

    async validateResources() {
        const currentMemory = await this.getMemoryUsage();
        const memoryHealthy = currentMemory < 500; // Less than 500MB
        
        return {
            healthy: memoryHealthy,
            memoryUsage: currentMemory,
            memoryStatus: memoryHealthy ? 'healthy' : 'high'
        };
    }

